import React, { useState, useEffect } from 'react';
import api from '../services/api';

export default function DriverPanel() {
  const user    = JSON.parse(localStorage.getItem('zipride_user') || '{}');
  const role    = user.role || 'PASSENGER';
  const isAdmin = role === 'ADMIN';

  const [drivers,     setDrivers]     = useState([]);
  const [form,        setForm]        = useState({ driverName:'', contactNumber:'', vehicleType:'SEDAN', vehicleNumber:'', status:'AVAILABLE', latitude:'', longitude:'', zone:'' });
  const [matchForm,   setMatchForm]   = useState({ pickupLat:'11.9416', pickupLng:'79.8083', topN:'3', zone:'', vehicleType:'SEDAN', passengerId:'1' });
  const [matchResult, setMatchResult] = useState(null);
  const [loading,     setLoading]     = useState(false);
  const [msg,         setMsg]         = useState('');

  useEffect(() => { fetchDrivers(); }, []);

  const fetchDrivers = async () => {
    try { const { data } = await api.get('/api/drivers'); setDrivers(data); } catch {}
  };

  const addDriver = async e => {
    e.preventDefault(); setMsg('');
    try {
      await api.post('/api/drivers', { ...form, latitude: parseFloat(form.latitude), longitude: parseFloat(form.longitude) });
      setMsg('✓ Driver added successfully.');
      setForm({ driverName:'', contactNumber:'', vehicleType:'SEDAN', vehicleNumber:'', status:'AVAILABLE', latitude:'', longitude:'', zone:'' });
      fetchDrivers();
    } catch (err) { setMsg('✗ ' + (err.response?.data?.message || 'Error adding driver.')); }
  };

  const findDrivers = async e => {
    e.preventDefault(); setLoading(true); setMatchResult(null);
    try {
      const { data } = await api.post('/api/drivers/find-nearest', {
        pickupLat: parseFloat(matchForm.pickupLat), pickupLng: parseFloat(matchForm.pickupLng),
        topN: parseInt(matchForm.topN), zone: matchForm.zone,
        vehicleType: matchForm.vehicleType, passengerId: parseInt(matchForm.passengerId)
      });
      setMatchResult(data);
    } catch (err) { setMatchResult({ message: err.response?.data?.message || 'Error' }); }
    finally { setLoading(false); }
  };

  const statusColor = s => s === 'AVAILABLE' ? 'var(--green)' : s === 'BUSY' ? 'var(--gold)' : 'var(--text-muted)';

  return (
    <>
      {/* ── ADMIN ONLY: Register Driver ──────────────────────────── */}
      {isAdmin && (
        <div className="panel">
          <div className="panel-header">
            <h3>Register Driver</h3>
            <span className="badge">ADMIN · POST /api/drivers</span>
          </div>
          <div className="panel-body">
            {msg && <div className={`alert ${msg.startsWith('✓') ? 'alert-success' : 'alert-error'}`}>{msg}</div>}
            <form onSubmit={addDriver}>
              <div className="form-row">
                <div className="form-group"><label>Driver Name</label><input placeholder="Ravi Kumar" value={form.driverName} onChange={e => setForm({...form, driverName: e.target.value})} /></div>
                <div className="form-group"><label>Contact</label><input placeholder="+91 9876543210" value={form.contactNumber} onChange={e => setForm({...form, contactNumber: e.target.value})} /></div>
              </div>
              <div className="form-row">
                <div className="form-group"><label>Vehicle Type</label>
                  <select value={form.vehicleType} onChange={e => setForm({...form, vehicleType: e.target.value})}>
                    {['AUTO','MINI','SEDAN','SUV','LUXURY'].map(v => <option key={v}>{v}</option>)}
                  </select>
                </div>
                <div className="form-group"><label>Vehicle Number</label><input placeholder="TN01AB1234" value={form.vehicleNumber} onChange={e => setForm({...form, vehicleNumber: e.target.value})} /></div>
              </div>
              <div className="form-row">
                <div className="form-group"><label>Latitude</label><input placeholder="11.9416" value={form.latitude} onChange={e => setForm({...form, latitude: e.target.value})} /></div>
                <div className="form-group"><label>Longitude</label><input placeholder="79.8083" value={form.longitude} onChange={e => setForm({...form, longitude: e.target.value})} /></div>
                <div className="form-group"><label>Zone</label><input placeholder="ZONE_A" value={form.zone} onChange={e => setForm({...form, zone: e.target.value})} /></div>
              </div>
              <button className="btn-action" type="submit">Add Driver</button>
            </form>
          </div>
        </div>
      )}

      {/* ── PASSENGER: Find Nearest Drivers ─────────────────────── */}
      <div className="panel">
        <div className="panel-header">
          <h3>🗺 Find Nearest Driver</h3>
          <span className="badge">POST /api/drivers/find-nearest</span>
        </div>
        <div className="panel-body">
          <form onSubmit={findDrivers}>
            <div className="form-row">
              <div className="form-group"><label>Pickup Latitude</label><input placeholder="11.9416" value={matchForm.pickupLat} onChange={e => setMatchForm({...matchForm, pickupLat: e.target.value})} /></div>
              <div className="form-group"><label>Pickup Longitude</label><input placeholder="79.8083" value={matchForm.pickupLng} onChange={e => setMatchForm({...matchForm, pickupLng: e.target.value})} /></div>
              <div className="form-group"><label>Top N Drivers</label>
                <select value={matchForm.topN} onChange={e => setMatchForm({...matchForm, topN: e.target.value})}>
                  {['1','2','3','4','5'].map(n => <option key={n}>{n}</option>)}
                </select>
              </div>
            </div>
            <div className="form-row">
              <div className="form-group"><label>Vehicle Type</label>
                <select value={matchForm.vehicleType} onChange={e => setMatchForm({...matchForm, vehicleType: e.target.value})}>
                  {['AUTO','MINI','SEDAN','SUV','LUXURY'].map(v => <option key={v}>{v}</option>)}
                </select>
              </div>
              <div className="form-group"><label>Zone (optional)</label><input placeholder="ZONE_A" value={matchForm.zone} onChange={e => setMatchForm({...matchForm, zone: e.target.value})} /></div>
            </div>
            <button className="btn-action" type="submit" disabled={loading}>
              {loading ? <><span className="spinner" /> Searching...</> : '🔍 Find Nearest Drivers'}
            </button>
          </form>

          {matchResult?.message && <div className="alert alert-error" style={{ marginTop:14 }}>{matchResult.message}</div>}

          {matchResult?.matchedDrivers && (
            <div style={{ marginTop:20 }}>
              <div style={{ fontSize:12, color:'var(--text-muted)', marginBottom:12 }}>
                {matchResult.matchedDrivers.length} driver(s) found
              </div>
              <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fill,minmax(240px,1fr))', gap:14 }}>
                {matchResult.matchedDrivers.map((d, i) => (
                  <div key={d.driverId} className="driver-card-match" style={{ animationDelay: `${i*0.07}s` }}>
                    <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start', marginBottom:10 }}>
                      <div>
                        <div style={{ fontSize:11, color:'var(--gold)', fontWeight:700, marginBottom:2 }}>#{i+1} NEAREST</div>
                        <div style={{ fontFamily:'Playfair Display', fontSize:16, fontWeight:700 }}>{d.driverName}</div>
                      </div>
                      <span style={{ padding:'3px 8px', borderRadius:99, fontSize:11, fontWeight:700,
                        background:`${statusColor(d.status)}22`, color:statusColor(d.status) }}>{d.status}</span>
                    </div>
                    <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:8 }}>
                      {[['📍 Distance', `${d.distanceKm?.toFixed(2)} km`],['⏱ ETA', `${d.etaMinutes} min`],['🚗 Vehicle', d.vehicleType],['⭐ Rating', d.averageRating?.toFixed(1)]].map(([k,v]) => (
                        <div key={k} style={{ background:'var(--bg-4)', borderRadius:8, padding:'8px 10px' }}>
                          <div style={{ fontSize:10, color:'var(--text-muted)', marginBottom:2 }}>{k}</div>
                          <div style={{ fontSize:13, fontWeight:600, color:'var(--text-pri)' }}>{v}</div>
                        </div>
                      ))}
                    </div>
                    {d.offerExpiresAt && (
                      <div style={{ marginTop:10, fontSize:11, color:'var(--text-muted)', display:'flex', alignItems:'center', gap:6 }}>
                        ⏳ Offer window: 30s
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>

      {/* ── Driver list: ADMIN sees all, PASSENGER sees available ── */}
      <div className="panel">
        <div className="panel-header">
          <h3>{isAdmin ? 'All Drivers' : 'Available Drivers'}</h3>
          <span className="badge">{drivers.length} total</span>
        </div>
        <div className="panel-body">
          {drivers.length === 0
            ? <p style={{ color:'var(--text-muted)', fontSize:13 }}>No drivers registered yet.</p>
            : <table className="data-table">
                <thead><tr><th>Name</th><th>Vehicle</th><th>Zone</th><th>Rating</th><th>Status</th></tr></thead>
                <tbody>
                  {drivers
                    .filter(d => isAdmin || d.status === 'AVAILABLE')
                    .map(d => (
                    <tr key={d.driverId}>
                      <td style={{ fontWeight:600 }}>{d.driverName}</td>
                      <td>{d.vehicleType}</td>
                      <td>{d.zone || '—'}</td>
                      <td style={{ color:'var(--gold)' }}>{'★'.repeat(Math.round(d.averageRating || 0))} {d.averageRating?.toFixed(1) || '—'}</td>
                      <td><span style={{ padding:'3px 8px', borderRadius:99, fontSize:11, fontWeight:700,
                        background:`${statusColor(d.status)}22`, color:statusColor(d.status) }}>{d.status}</span></td>
                    </tr>
                  ))}
                </tbody>
              </table>
          }
        </div>
      </div>
    </>
  );
}
